import{_ as e,o as s,c as n,a2 as t}from"./chunks/framework.DCVnL8g5.js";const h=JSON.parse('{"title":"Entidades casos de uso y adaptadores","description":"","frontmatter":{},"headers":[],"relativePath":"full-stack/arquitectura/clean-architecture/03-entidades-casos-de-uso-y-adaptadores.md","filePath":"full-stack/arquitectura/clean-architecture/03-entidades-casos-de-uso-y-adaptadores.md","lastUpdated":1782521464000}'),o={name:"full-stack/arquitectura/clean-architecture/03-entidades-casos-de-uso-y-adaptadores.md"};function i(r,a,d,l,p,c){return s(),n("div",null,[...a[0]||(a[0]=[t(`<h1 id="entidades-casos-de-uso-y-adaptadores" tabindex="-1">Entidades casos de uso y adaptadores <a class="header-anchor" href="#entidades-casos-de-uso-y-adaptadores" aria-label="Permalink to &quot;Entidades casos de uso y adaptadores&quot;">​</a></h1><p>Estos tres conceptos forman el nucleo operativo de Clean Architecture. Las entidades protegen reglas, los casos de uso expresan acciones y los adaptadores conectan el sistema con el exterior.</p><h2 id="entidades" tabindex="-1">Entidades <a class="header-anchor" href="#entidades" aria-label="Permalink to &quot;Entidades&quot;">​</a></h2><p>Una entidad representa algo importante para el negocio y mantiene sus invariantes.</p><div class="language-txt vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">txt</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Order</span></span>
<span class="line"><span>  id</span></span>
<span class="line"><span>  customerId</span></span>
<span class="line"><span>  lines</span></span>
<span class="line"><span>  status</span></span>
<span class="line"><span>  total</span></span></code></pre></div><p>Una entidad no deberia ser una bolsa de getters y setters. Debe impedir estados invalidos.</p><div class="language-txt vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">txt</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Order.confirm()</span></span>
<span class="line"><span>  - no se puede confirmar si no tiene lineas</span></span>
<span class="line"><span>  - no se puede confirmar si ya esta cancelado</span></span>
<span class="line"><span>  - recalcula el total antes de confirmar</span></span></code></pre></div><h2 id="casos-de-uso" tabindex="-1">Casos de uso <a class="header-anchor" href="#casos-de-uso" aria-label="Permalink to &quot;Casos de uso&quot;">​</a></h2><p>Un caso de uso representa una accion completa que aporta valor.</p><p>Ejemplos:</p><ul><li>CreateOrder.</li><li>ConfirmOrder.</li><li>CancelSubscription.</li><li>GenerateMonthlyInvoice.</li><li>PublishArticle.</li></ul><p>Un caso de uso suele validar la intencion, cargar entidades, ejecutar reglas, persistir cambios y publicar eventos o devolver una respuesta.</p><h2 id="puertos" tabindex="-1">Puertos <a class="header-anchor" href="#puertos" aria-label="Permalink to &quot;Puertos&quot;">​</a></h2><p>Un puerto es un contrato que el caso de uso necesita.</p><div class="language-txt vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">txt</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>interface OrderRepository</span></span>
<span class="line"><span>  findById(id)</span></span>
<span class="line"><span>  save(order)</span></span></code></pre></div><p>El caso de uso depende del puerto. La base de datos concreta implementa ese puerto.</p><h2 id="adaptadores" tabindex="-1">Adaptadores <a class="header-anchor" href="#adaptadores" aria-label="Permalink to &quot;Adaptadores&quot;">​</a></h2><p>Los adaptadores traducen entre el mundo externo y el mundo interno.</p><div class="language-txt vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">txt</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>HTTP request -&gt; DTO -&gt; caso de uso -&gt; response</span></span>
<span class="line"><span>SQL row -&gt; entidad</span></span>
<span class="line"><span>Evento Kafka -&gt; comando interno</span></span></code></pre></div><p>Hay adaptadores de entrada y de salida:</p><ul><li>Entrada: controladores, consumers, jobs, CLI.</li><li>Salida: repositorios, gateways, clientes HTTP, colas, filesystem.</li></ul><h2 id="flujo-completo" tabindex="-1">Flujo completo <a class="header-anchor" href="#flujo-completo" aria-label="Permalink to &quot;Flujo completo&quot;">​</a></h2><div class="language-txt vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">txt</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Cliente HTTP</span></span>
<span class="line"><span>  -&gt; Controller</span></span>
<span class="line"><span>  -&gt; CreateOrderCommand</span></span>
<span class="line"><span>  -&gt; CreateOrderUseCase</span></span>
<span class="line"><span>  -&gt; Order</span></span>
<span class="line"><span>  -&gt; OrderRepository</span></span>
<span class="line"><span>  -&gt; SqlOrderRepository</span></span>
<span class="line"><span>  -&gt; PostgreSQL</span></span></code></pre></div><h2 id="errores-habituales" tabindex="-1">Errores habituales <a class="header-anchor" href="#errores-habituales" aria-label="Permalink to &quot;Errores habituales&quot;">​</a></h2><ul><li>Llamar entidad a cualquier tabla.</li><li>Poner validaciones criticas solo en DTOs.</li><li>Crear un caso de uso por cada metodo CRUD sin pensar en intenciones reales.</li><li>Hacer que los adaptadores devuelvan objetos de librerias externas hacia dentro.</li><li>Crear interfaces genericas para todo sin necesidad.</li></ul><h2 id="ejercicio" tabindex="-1">Ejercicio <a class="header-anchor" href="#ejercicio" aria-label="Permalink to &quot;Ejercicio&quot;">​</a></h2><p>Toma una funcionalidad CRUD existente y renombrala como intencion de negocio. Por ejemplo, cambia <code>updateUser</code> por <code>ChangeUserEmail</code>, <code>DeactivateUser</code> o <code>AcceptInvitation</code>. Despues identifica entidad, caso de uso, puertos y adaptadores.</p>`,27)])])}const m=e(o,[["render",i]]);export{h as __pageData,m as default};
